    13→// validateJSONAgainstSchema validates a JSON document against a schema file path (relative to repo root)
    14→func validateJSONAgainstSchema(data []byte, schemaRelPath string) error {
    15→    abs, err := filepath.Abs(schemaRelPath)
    16→    if err != nil { return fmt.Errorf("resolve schema path: %w", err) }
    17→    
    18→    schemaBytes, err := os.ReadFile(abs)
    19→    if err != nil { return fmt.Errorf("read schema file: %w", err) }
    20→    
    21→    compiler := jsonschema.NewCompiler()
    22→    if err := compiler.AddResource("schema.json", strings.NewReader(string(schemaBytes))); err != nil {
    23→        return fmt.Errorf("add schema: %w", err)
    24→    }
    25→    sch, err := compiler.Compile("schema.json")
    26→    if err != nil { return fmt.Errorf("compile schema: %w", err) }
    27→    var v any
    28→    if err := json.Unmarshal(data, &v); err != nil {
    29→        return fmt.Errorf("invalid json: %w", err)
    30→    }
    31→    if err := sch.Validate(v); err != nil {
    32→        return fmt.Errorf("schema validation failed: %w", err)
    33→    }
    34→    return nil
    35→}
